// src/components/MapComponent/index.jsx

import React from 'react';
import { YMaps, Map, Placemark } from '@pbe/react-yandex-maps'; 

// Координаты для Дубининской ул., 96, Москва (iThub College)
const CENTER_COORDS = [55.7196, 37.6366]; 

const YandexMapComponent = () => {

    // API-ключ: Для большинства некоммерческих сайтов не обязателен.
    const apiKey = '6be8c5e5-e21b-400b-93d4-6d27f718c822'; // Оставьте пустым

    const mapState = {
        center: CENTER_COORDS, 
        zoom: 16, 
        // Включаем основные элементы управления
        controls: ["zoomControl", "fullscreenControl", "rulerControl"] 
    };

    return (
        <YMaps query={{ apikey: apiKey }}>
            <Map 
                defaultState={mapState}
                // Критично: карта займет всю ширину и высоту родительского контейнера (.mapContainer)
                width="100%"
                height="100%" 
                modules={["control.ZoomControl", "control.FullscreenControl"]} // Загрузка модулей
            >
                {/* Установка метки (Placemark) на заданных координатах */}
                <Placemark 
                    geometry={CENTER_COORDS} 
                    options={{ preset: 'islands#darkGreenDotIcon' }} // Зеленая метка
                    properties={{ hintContent: "Наш адрес: Дубининская ул., 96" }}
                />
            </Map>
        </YMaps>
    );
};

export default YandexMapComponent;
